148→    fn should_attempt_auth_connection(
149→        has_existing_auth_provider: bool,
150→        has_oauth_override: bool,
151→        has_stored_token: bool,
152→    ) -> bool {
153→        has_existing_auth_provider || has_oauth_override || has_stored_token
154→    }
