  1→//! Import MCP server configuration from OpenClaw.
  2→//!
  3→//! Merges OpenClaw's `mcp-servers.json` into Moltis's MCP registry,
  4→//! skipping servers with duplicate names.
  5→
  6→use std::{collections::HashMap, path::Path};
  7→
  8→use tracing::debug;
  9→
 10→use crate::{
 11→    detect::OpenClawDetection,
 12→    report::{CategoryReport, ImportCategory, ImportStatus},
 13→    types::OpenClawMcpServer,
 14→};
 15→
 16→/// Import MCP servers from OpenClaw into the Moltis MCP registry.
 17→///
 18→/// `dest_mcp_path` is the path to Moltis's `mcp-servers.json`.
 19→pub fn import_mcp_servers(detection: &OpenClawDetection, dest_mcp_path: &Path) -> CategoryReport {
 20→    let src_path = detection.home_dir.join("mcp-servers.json");
 21→    if !src_path.is_file() {
 22→        return CategoryReport::skipped(ImportCategory::McpServers);
 23→    }
 24→
 25→    let src_servers = match load_mcp_servers(&src_path) {
 26→        Ok(s) => s,
 27→        Err(e) => {
 28→            return CategoryReport::failed(
 29→                ImportCategory::McpServers,
 30→                format!("failed to parse OpenClaw mcp-servers.json: {e}"),
 31→            );
 32→        },
 33→    };
 34→
 35→    if src_servers.is_empty() {
 36→        return CategoryReport::skipped(ImportCategory::McpServers);
 37→    }
 38→
 39→    // Load existing Moltis MCP servers
 40→    let mut existing = if dest_mcp_path.is_file() {
 41→        load_mcp_servers(dest_mcp_path).unwrap_or_default()
 42→    } else {
 43→        HashMap::new()
 44→    };
 45→
 46→    let mut imported = 0;
 47→    let mut skipped = 0;
 48→
 49→    for (name, server) in &src_servers {
 50→        if existing.contains_key(name) {
 51→            debug!(name, "MCP server already exists, skipping");
 52→            skipped += 1;
 53→            continue;
 54→        }
 55→
 56→        debug!(name, command = %server.command, "importing MCP server");
 57→        existing.insert(name.clone(), server.clone());
 58→        imported += 1;
 59→    }
 60→
 61→    if imported > 0 {
 62→        if let Some(parent) = dest_mcp_path.parent()
 63→            && let Err(e) = std::fs::create_dir_all(parent)
 64→        {
 65→            return CategoryReport::failed(
 66→                ImportCategory::McpServers,
 67→                format!("failed to create directory: {e}"),
 68→            );
 69→        }
 70→        let json = match serde_json::to_string_pretty(&existing) {
 71→            Ok(j) => j,
 72→            Err(e) => {
 73→                return CategoryReport::failed(
 74→                    ImportCategory::McpServers,
 75→                    format!("failed to serialize MCP servers: {e}"),
 76→                );
 77→            },
 78→        };
 79→        if let Err(e) = std::fs::write(dest_mcp_path, json) {
 80→            return CategoryReport::failed(
 81→                ImportCategory::McpServers,
 82→                format!("failed to write mcp-servers.json: {e}"),
 83→            );
 84→        }
 85→    }
 86→
 87→    let status = if imported == 0 {
 88→        ImportStatus::Skipped
 89→    } else {
 90→        ImportStatus::Success
 91→    };
 92→
 93→    CategoryReport {
 94→        category: ImportCategory::McpServers,
 95→        status,
 96→        items_imported: imported,
 97→        items_updated: 0,
 98→        items_skipped: skipped,
 99→        warnings: Vec::new(),
100→        errors: Vec::new(),

