  1→const { expect } = require("@playwright/test");
  2→
  3→/**
  4→ * Wait until the SPA has mounted visible content into #pageContent.
  5→ * This is a stable cross-route readiness signal for the app shell.
  6→ */
  7→async function expectPageContentMounted(page) {
  8→	await expect
  9→		.poll(
 10→			async () => {
 11→				try {
 12→					return await page.evaluate(() => {
 13→						const el = document.getElementById("pageContent");
 14→						if (!el) return 0;
 15→						return el.childElementCount;
 16→					});
 17→				} catch (error) {
 18→					if (isRetryableNavigationError(error)) return 0;
 19→					throw error;
 20→				}
 21→			},
 22→			{
 23→				timeout: 20_000,
 24→			},
 25→		)
 26→		.toBeGreaterThan(0);
 27→}
 28→
 29→/**
 30→ * Collect uncaught page errors for later assertion.
 31→ * Returns an array that fills as errors occur.
 32→ *
 33→ * Usage:
 34→ *   const pageErrors = watchPageErrors(page);
 35→ *   // ... interact with page ...
 36→ *   expect(pageErrors).toEqual([]);
 37→ */
 38→function watchPageErrors(page) {
 39→	const pageErrors = [];
 40→	page.on("pageerror", (err) => pageErrors.push(err.message));
 41→	return pageErrors;
 42→}
 43→
 44→/**
 45→ * Wait for the WebSocket connection status dot to reach "connected".
 46→ * Note: #statusText is intentionally set to "" when connected, so we
 47→ * only check the dot's CSS class.
 48→ */
 49→async function waitForWsConnected(page, timeoutMs = 20_000) {
 50→	await expect
 51→		.poll(
 52→			async () => {
 53→				const statusDotConnected = await page
 54→					.locator("#statusDot")
 55→					.getAttribute("class")
 56→					.then((cls) => /connected/.test(cls || ""))
 57→					.catch(() => false);
 58→				if (!statusDotConnected) return false;
 59→				return page
 60→					.evaluate(async () => {
 61→						const appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
 62→						if (!appScript) return false;
 63→						const appUrl = new URL(appScript.src, window.location.origin);
 64→						const prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
 65→						const state = await import(`${prefix}js/state.js`);
 66→						return Boolean(state.connected && state.ws && state.ws.readyState === WebSocket.OPEN);
 67→					})
 68→					.catch(() => false);
 69→			},
 70→			{ timeout: timeoutMs },
 71→		)
 72→		.toBe(true);
 73→}
 74→
 75→function isRetryableNavigationError(error) {
 76→	var message = error?.message || String(error || "");
 77→	return (
 78→		message.includes("net::ERR_ABORTED") ||
 79→		message.includes("Execution context was destroyed") ||
 80→		message.includes("Target page, context or browser has been closed")
 81→	);
 82→}
 83→
 84→/**
 85→ * Navigate to a path, wait for SPA content to mount, and assert no errors.
 86→ * Returns the pageErrors array for further assertions.
 87→ */
 88→async function navigateAndWait(page, path) {
 89→	const pageErrors = watchPageErrors(page);
 90→	let lastError = null;
 91→	for (let attempt = 0; attempt < 3; attempt++) {
 92→		try {
 93→			await page.goto(path, { waitUntil: "domcontentloaded" });
 94→			await expectPageContentMounted(page);
 95→			return pageErrors;
 96→		} catch (error) {
 97→			lastError = error;
 98→			if (!isRetryableNavigationError(error) || attempt === 2) {
 99→				break;
100→			}
101→		}
102→	}
103→	if (lastError) throw lastError;
104→	return pageErrors;
105→}
106→
107→/**
108→ * Create a new session by clicking the new-session button.
109→ * Waits for the active key to change, URL to update, and content to mount.
110→ *
111→ * Note: we intentionally do NOT wait for the session to appear in the
112→ * sessions list (store.getByKey). The list is populated asynchronously
113→ * by the sessions.switch RPC and can be slow under heavy test load.
114→ * The key change + URL match + page mount are sufficient to prove the
115→ * session was created; individual tests can wait for store indexing
116→ * if their assertions require it.
117→ */
118→async function createSession(page) {
119→	const timeoutMs = 20_000;
120→	const previousActiveKey = await page.evaluate(() => {
121→		return window.__moltis_stores?.sessionStore?.activeSessionKey?.value || "";
122→	});
123→
124→	await page.locator("#newSessionBtn").click();
125→	await expect
126→		.poll(
127→			() =>
128→				page.evaluate(() => {
129→					return window.__moltis_stores?.sessionStore?.activeSessionKey?.value || "";
130→				}),
131→			{ timeout: timeoutMs },
132→		)
133→		.not.toBe(previousActiveKey);
134→
135→	await expect
136→		.poll(
137→			() =>
138→				page.evaluate(() => {
139→					const key = window.__moltis_stores?.sessionStore?.activeSessionKey?.value || "";
140→					if (!key) return false;
141→					return window.location.pathname === `/chats/${key.replace(/:/g, "/")}`;
142→				}),
143→			{ timeout: timeoutMs },
144→		)
145→		.toBe(true);
146→
147→	await expectPageContentMounted(page);
148→}
149→
150→/**
151→ * Open the chat "More controls" modal and wait for it to be visible.
152→ */
153→async function openChatMoreModal(page) {
154→	const modal = page.locator("#chatMoreModal");
155→	if (await modal.isVisible().catch(() => false)) return modal;
156→	await expect(page.locator("#chatMoreBtn")).toBeVisible({ timeout: 10_000 });
157→	await page.locator("#chatMoreBtn").click();
158→	await expect(modal).toBeVisible({ timeout: 10_000 });
159→	return modal;
160→}
161→
162→/**
163→ * Close the chat "More controls" modal by clicking the backdrop.
164→ */
165→async function closeChatMoreModal(page) {
166→	const modal = page.locator("#chatMoreModal");
167→	if (!(await modal.isVisible().catch(() => false))) return;
168→	await modal.click({ position: { x: 8, y: 8 } });
169→	await expect(modal).toBeHidden({ timeout: 10_000 });
170→}
171→
172→module.exports = {
173→	expectPageContentMounted,
174→	watchPageErrors,
175→	waitForWsConnected,
176→	navigateAndWait,
177→	createSession,
178→	openChatMoreModal,
179→	closeChatMoreModal,
180→};
