 44→	return new Promise((resolve) => {
 45→		var chunks = [];
 46→		req.on("data", (c) => chunks.push(c));
 47→		req.on("end", () => {
 48→			var body = Buffer.concat(chunks).toString();
 49→			resolve(new URLSearchParams(body));
 50→		});
 51→	});
 52→}
 53→
 54→function respond(res, status, body) {
 55→	var json = JSON.stringify(body);
 56→	res.writeHead(status, { "Content-Type": "application/json" });
 57→	res.end(json);
 58→}
 59→
 60→function handleAuthorize(res, query) {
 61→	if (!(query.client_id && query.redirect_uri && query.code_challenge && query.state)) {
 62→		return respond(res, 400, {
 63→			error: "invalid_request",
 64→			error_description: "Missing required parameters: client_id, redirect_uri, code_challenge, state",
 65→		});
 66→	}
 67→	if (query.code_challenge_method !== "S256") {
 68→		return respond(res, 400, {
 69→			error: "invalid_request",
 70→			error_description: "Only S256 code_challenge_method is supported",
 71→		});
 72→	}
 73→
 74→	pendingFlows.set(query.state, {
 75→		challenge: query.code_challenge,
 76→		redirectUri: query.redirect_uri,
 77→	});
 78→
 79→	var authCode = `mock-auth-code-${crypto.randomBytes(8).toString("hex")}`;
 80→	issuedCodes.set(authCode, { state: query.state });
 81→
 82→	var redirectUrl = new URL(query.redirect_uri);
 83→	redirectUrl.searchParams.set("code", authCode);
 84→	redirectUrl.searchParams.set("state", query.state);
 85→	lastRedirectUrl = redirectUrl.toString();
 86→
 87→	if (authorizeShouldNotRedirect) {
 88→		return respond(res, 200, {
 89→			ok: true,
 90→			note: "authorize_should_not_redirect is enabled",
 91→			redirect_url: lastRedirectUrl,
 92→		});
 93→	}
 94→
 95→	res.writeHead(302, { Location: redirectUrl.toString() });
 96→	res.end();
 97→}
 98→
 99→function handleTokenExchange(res, body) {
100→	var authCode = body.get("code");
101→	var verifier = body.get("code_verifier");
102→	var clientId = body.get("client_id");
103→
104→	if (!(authCode && verifier && clientId)) {
105→		return respond(res, 400, {
106→			error: "invalid_request",
107→			error_description: "Missing code, code_verifier, or client_id",
108→		});
109→	}
110→
111→	var codeEntry = issuedCodes.get(authCode);
112→	if (!codeEntry) {
113→		return respond(res, 400, {
114→			error: "invalid_grant",
115→			error_description: "Unknown or expired authorization code",
116→		});
117→	}
118→
119→	var flow = pendingFlows.get(codeEntry.state);
120→	if (!flow) {
121→		return respond(res, 400, {
122→			error: "invalid_grant",
123→			error_description: "No pending flow for this state",
124→		});
125→	}
126→
127→	if (!verifyPkce(verifier, flow.challenge)) {
128→		return respond(res, 400, {
129→			error: "invalid_grant",
130→			error_description: "PKCE verification failed",
131→		});
132→	}
133→
134→	issuedCodes.delete(authCode);
135→	pendingFlows.delete(codeEntry.state);
136→
137→	return respond(res, 200, {
138→		access_token: `mock-access-token-${crypto.randomBytes(8).toString("hex")}`,
139→		refresh_token: `mock-refresh-token-${crypto.randomBytes(8).toString("hex")}`,
140→		token_type: "Bearer",
141→		expires_in: 3600,
142→	});
143→}
144→
145→function handleTokenRefresh(res, body) {
146→	var refreshToken = body.get("refresh_token");
147→	if (!refreshToken) {
148→		return respond(res, 400, {
149→			error: "invalid_request",
150→			error_description: "Missing refresh_token",
151→		});
152→	}
153→
154→	return respond(res, 200, {
155→		access_token: `mock-refreshed-token-${crypto.randomBytes(8).toString("hex")}`,
156→		refresh_token: `mock-refresh-token-${crypto.randomBytes(8).toString("hex")}`,
157→		token_type: "Bearer",
158→		expires_in: 3600,
159→	});
160→}
161→
162→async function handleToken(res, req) {
163→	var body = await parseBody(req);
164→	var grantType = body.get("grant_type");
165→
166→	if (tokenShouldFail) {
167→		return respond(res, 400, {
168→			error: "server_error",
169→			error_description: "Mock server configured to return errors",
170→		});
171→	}
172→
173→	if (grantType === "authorization_code") {
174→		return handleTokenExchange(res, body);
175→	}
176→	if (grantType === "refresh_token") {
177→		return handleTokenRefresh(res, body);
178→	}
179→
180→	return respond(res, 400, {
181→		error: "unsupported_grant_type",
182→		error_description: `Unsupported grant_type: ${grantType}`,
183→	});
184→}
185→
186→async function handleConfig(req) {
187→	var configBody = await parseBody(req);
188→	if (configBody.has("token_should_fail")) {
189→		tokenShouldFail = configBody.get("token_should_fail") === "true";
190→	}
191→	if (configBody.has("authorize_should_not_redirect")) {
192→		authorizeShouldNotRedirect = configBody.get("authorize_should_not_redirect") === "true";
193→	}
194→}
195→
196→function handleReset() {
197→	calls = [];
198→	pendingFlows.clear();
199→	issuedCodes.clear();
200→	tokenShouldFail = false;
201→	authorizeShouldNotRedirect = false;
202→	lastRedirectUrl = null;
203→}
204→
205→var server = http.createServer(async (req, res) => {
206→	var parsed = parseRequestUrl(req);
207→	var pathname = parsed.pathname;
208→	var query = queryObject(parsed.searchParams);
209→
210→	calls.push({
211→		method: req.method,
212→		path: pathname,
213→		query,
214→		timestamp: Date.now(),
215→	});
216→
217→	if (req.method === "GET" && pathname === "/authorize") {
218→		return handleAuthorize(res, query);
219→	}
220→	if (req.method === "POST" && pathname === "/token") {
221→		return handleToken(res, req);
222→	}
223→	if (req.method === "GET" && pathname === "/calls") {
224→		return respond(res, 200, calls);
225→	}
226→	if (req.method === "GET" && pathname === "/last-redirect") {
227→		return respond(res, 200, { redirect_url: lastRedirectUrl });
228→	}
229→	if (req.method === "POST" && pathname === "/config") {
230→		await handleConfig(req);
231→		return respond(res, 200, { ok: true });
232→	}
233→	if (req.method === "POST" && pathname === "/reset") {
234→		handleReset();
235→		return respond(res, 200, { ok: true });
236→	}
237→
238→	respond(res, 404, { error: "not_found" });
239→});
240→
241→server.listen(0, "127.0.0.1", () => {
242→	var port = server.address().port;
243→	process.stdout.write(`${JSON.stringify({ port })}\n`);
244→});
