 12→
 13→/// Recursively strip null values from nested objects and arrays.
 14→///
 15→/// Top-level null stripping is handled by the caller; this recurses into
 16→/// values that are themselves objects or arrays.
 17→fn strip_nulls_recursive(map: &mut serde_json::Map<String, serde_json::Value>) {
 18→    for value in map.values_mut() {
 19→        match value {
 20→            serde_json::Value::Object(inner) => {
 21→                inner.retain(|_, v| !v.is_null());
 22→                strip_nulls_recursive(inner);
 23→            },
 24→            serde_json::Value::Array(arr) => {
 25→                for item in arr.iter_mut() {
 26→                    if let serde_json::Value::Object(inner) = item {
 27→                        inner.retain(|_, v| !v.is_null());
 28→                        strip_nulls_recursive(inner);
 29→                    }
 30→                }
 31→            },
 32→            _ => {},
 33→        }
 34→    }
 35→}
 36→
 37→/// An `AgentTool` implementation that delegates to an MCP server via `McpClient`.
 38→pub struct McpToolBridge {
 39→    /// Prefixed tool name: `mcp__<server>__<tool>`.
 40→    prefixed_name: String,
 41→    /// Original tool name on the MCP server.
 42→    original_name: String,
 43→    /// Name of the MCP server this tool belongs to.
 44→    server_name: String,
 45→    description: String,
 46→    input_schema: serde_json::Value,
 47→    client: Arc<tokio::sync::RwLock<dyn McpClientTrait>>,
 48→}
 49→
 50→impl McpToolBridge {
 51→    /// Create a bridge for a single MCP tool.
 52→    pub fn new(
 53→        server_name: &str,
 54→        tool_def: &McpToolDef,
 55→        client: Arc<tokio::sync::RwLock<dyn McpClientTrait>>,
 56→    ) -> Self {
 57→        Self {
 58→            prefixed_name: format!("mcp__{}__{}", server_name, tool_def.name),
 59→            original_name: tool_def.name.clone(),
 60→            server_name: server_name.to_string(),
 61→            description: tool_def
 62→                .description
 63→                .clone()
 64→                .unwrap_or_else(|| format!("MCP tool: {}", tool_def.name)),
 65→            input_schema: tool_def.input_schema.clone(),
 66→            client,
 67→        }
 68→    }
 69→
 70→    /// Create bridges for all tools from a client.
 71→    pub fn from_client(
 72→        server_name: &str,
 73→        tools: &[McpToolDef],
 74→        client: Arc<tokio::sync::RwLock<dyn McpClientTrait>>,
 75→    ) -> Vec<Self> {
 76→        tools
 77→            .iter()
 78→            .map(|t| Self::new(server_name, t, Arc::clone(&client)))
 79→            .collect()
 80→    }
 81→
 82→    pub fn prefixed_name(&self) -> &str {
 83→        &self.prefixed_name
 84→    }
 85→
 86→    /// The name of the MCP server this tool belongs to.
 87→    pub fn server_name(&self) -> &str {
 88→        &self.server_name
 89→    }
 90→}
 91→
 92→/// Trait for agent-callable tools, matching `AgentTool` in moltis-agents.
 93→///
 94→/// We define our own copy here to avoid a circular dependency on moltis-agents.
 95→/// The gateway wires `McpToolBridge` into the `ToolRegistry` via a thin adapter.
 96→#[async_trait]
 97→pub trait McpAgentTool: Send + Sync {
 98→    fn name(&self) -> &str;
 99→    fn description(&self) -> &str;
100→    fn parameters_schema(&self) -> serde_json::Value;
101→    async fn execute(&self, params: serde_json::Value) -> Result<serde_json::Value>;
102→}
103→
104→#[async_trait]
105→impl McpAgentTool for McpToolBridge {
106→    fn name(&self) -> &str {
107→        &self.prefixed_name
108→    }
109→
110→    fn description(&self) -> &str {
111→        &self.description
112→    }
113→
114→    fn parameters_schema(&self) -> serde_json::Value {
115→        self.input_schema.clone()
116→    }
117→
118→    async fn execute(&self, params: serde_json::Value) -> Result<serde_json::Value> {
119→        // Clean up arguments before forwarding to the MCP server:
120→        // 1. Strip internal metadata keys (e.g. _session_key) injected by the
121→        //    agent runner — these break servers with strict validation.
122→        // 2. Strip null values — these arise from strict-mode schema patching
123→        //    that makes optional properties nullable.  MCP servers expect
124→        //    optional fields to be absent, not null.
125→        let params = match params {
126→            serde_json::Value::Object(mut map) => {
127→                map.retain(|k, v| !k.starts_with('_') && !v.is_null());
128→                strip_nulls_recursive(&mut map);
129→                serde_json::Value::Object(map)
130→            },
131→            other => other,
132→        };
133→
134→        let client = self.client.read().await;
135→        let result = client.call_tool(&self.original_name, params).await?;
136→
137→        if result.is_error {
138→            let text = result
139→                .content
140→                .iter()
141→                .filter_map(|c| match c {
142→                    ToolContent::Text { text } => Some(text.as_str()),
143→                    _ => None,
144→                })
145→                .collect::<Vec<_>>()
146→                .join("\n");
147→            return Err(Error::message(format!("MCP tool error: {text}")));
148→        }
149→
150→        // Flatten text content into a single JSON value.

