  1→//! Live MCP service implementation backed by `McpManager`.
  2→
  3→use std::{collections::HashMap, sync::Arc};
  4→
  5→use {
  6→    async_trait::async_trait,
  7→    serde_json::Value,
  8→    tokio::sync::RwLock,
  9→    tracing::{info, warn},
 10→};
 11→
 12→use moltis_agents::tool_registry::ToolRegistry;
 13→
 14→use crate::services::{McpService, ServiceError, ServiceResult};
 15→
 16→// Re-export pure parsing functions that now live in moltis-mcp.
 17→pub(crate) use moltis_mcp::{merge_env_overrides, parse_server_config};
 18→
 19→// Re-export sync_mcp_tools from the dedicated bridge crate.
 20→pub(crate) use moltis_mcp_agent_bridge::sync_mcp_tools;
 21→
 22→// ── Config parsing helper ───────────────────────────────────────────────────
 23→
 24→// Extract an `McpServerConfig` from JSON params.
 25→// ── LiveMcpService ──────────────────────────────────────────────────────────
 26→
 27→/// Live MCP service delegating to `McpManager`.
 28→pub struct LiveMcpService {
 29→    manager: Arc<moltis_mcp::McpManager>,
 30→    /// Shared tool registry for syncing MCP tools into the agent loop.
 31→    /// Set after construction via `set_tool_registry`.
 32→    tool_registry: RwLock<Option<Arc<RwLock<ToolRegistry>>>>,
 33→    config_env_overrides: HashMap<String, String>,
 34→    credential_store: RwLock<Option<Arc<crate::auth::CredentialStore>>>,
 35→}
 36→
 37→impl LiveMcpService {
 38→    pub fn new(
 39→        manager: Arc<moltis_mcp::McpManager>,
 40→        config_env_overrides: HashMap<String, String>,
 41→        credential_store: Option<Arc<crate::auth::CredentialStore>>,
 42→    ) -> Self {
 43→        Self {
 44→            manager,
 45→            tool_registry: RwLock::new(None),
 46→            config_env_overrides,
 47→            credential_store: RwLock::new(credential_store),
 48→        }
 49→    }
 50→
 51→    /// Store a reference to the shared tool registry so MCP mutations
 52→    /// can automatically sync tools.
 53→    pub async fn set_tool_registry(&self, registry: Arc<RwLock<ToolRegistry>>) {
 54→        *self.tool_registry.write().await = Some(registry);
 55→    }
 56→
 57→    /// Sync MCP tools into the shared tool registry (if set).
 58→    pub async fn sync_tools_if_ready(&self) {
 59→        let maybe_reg = self.tool_registry.read().await.clone();
 60→        if let Some(reg) = maybe_reg {
 61→            sync_mcp_tools(&self.manager, &reg).await;
 62→        }
 63→    }
 64→
 65→    /// Access the underlying manager.
 66→    pub fn manager(&self) -> &Arc<moltis_mcp::McpManager> {
 67→        &self.manager
 68→    }
 69→
 70→    pub async fn set_credential_store(&self, credential_store: Arc<crate::auth::CredentialStore>) {
 71→        *self.credential_store.write().await = Some(credential_store);
 72→    }
 73→
 74→    async fn refresh_manager_env_overrides(&self) {
 75→        let credential_store = self.credential_store.read().await.clone();
 76→        let env_overrides = if let Some(store) = credential_store {
 77→            match store.get_all_env_values().await {
 78→                Ok(db_env_vars) => merge_env_overrides(&self.config_env_overrides, db_env_vars),
 79→                Err(error) => {
 80→                    warn!(%error, "failed to refresh MCP env overrides from credential store");
 81→                    self.config_env_overrides.clone()
 82→                },
 83→            }
 84→        } else {
 85→            self.config_env_overrides.clone()
 86→        };
 87→
 88→        self.manager.set_env_overrides(env_overrides).await;
 89→    }
 90→}
 91→
 92→#[async_trait]
 93→impl McpService for LiveMcpService {
 94→    async fn list(&self) -> ServiceResult {
 95→        let statuses = self.manager.status_all().await;
 96→        Ok(serde_json::to_value(&statuses)?)
 97→    }
 98→
 99→    async fn add(&self, params: Value) -> ServiceResult {
100→        let name = params
101→            .get("name")
102→            .and_then(|v| v.as_str())
103→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
104→        let redirect_uri = params
105→            .get("redirectUri")
106→            .and_then(|v| v.as_str())
107→            .map(str::trim)
108→            .filter(|v| !v.is_empty())
109→            .map(ToOwned::to_owned);
110→        let config =
111→            parse_server_config(&params, None).map_err(|e| ServiceError::message(e.to_string()))?;
112→        self.refresh_manager_env_overrides().await;
113→
114→        // If a server with this name already exists, append a numeric suffix.
115→        let final_name = {
116→            let reg = self.manager.registry_snapshot().await;
117→            let mut candidate = name.to_string();
118→            let mut n = 2u32;
119→            while reg.servers.contains_key(&candidate) {
120→                candidate = format!("{name}-{n}");
121→                n += 1;
122→            }
123→            candidate
124→        };
125→
126→        info!(server = %final_name, "adding MCP server via API");
127→        match self
128→            .manager
129→            .add_server(final_name.clone(), config, true)
130→            .await
131→        {
132→            Ok(_) => {
133→                self.sync_tools_if_ready().await;
134→                Ok(serde_json::json!({ "ok": true, "name": final_name }))
135→            },
136→            Err(e) => {
137→                if matches!(
138→                    e,
139→                    moltis_mcp::Error::Manager(moltis_mcp::McpManagerError::OAuthRequired { .. })
140→                ) {
141→                    if let Some(uri) = redirect_uri {
142→                        let auth_url = self
143→                            .manager
144→                            .oauth_start_server(&final_name, &uri)
145→                            .await
146→                            .map_err(ServiceError::message)?;
147→                        Ok(serde_json::json!({
148→                            "ok": true,
149→                            "name": final_name,
150→                            "oauthPending": true,
151→                            "authUrl": auth_url
152→                        }))
153→                    } else {
154→                        Ok(serde_json::json!({
155→                            "ok": true,
156→                            "name": final_name,
157→                            "oauthPending": true
158→                        }))
159→                    }
160→                } else {
161→                    Err(ServiceError::message(e))
162→                }
163→            },
164→        }
165→    }
166→
167→    async fn remove(&self, params: Value) -> ServiceResult {
168→        let name = params
169→            .get("name")
170→            .and_then(|v| v.as_str())
171→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
172→
173→        let removed = self
174→            .manager
175→            .remove_server(name)
176→            .await
177→            .map_err(ServiceError::message)?;
178→
179→        self.sync_tools_if_ready().await;
180→
181→        Ok(serde_json::json!({ "removed": removed }))
182→    }
183→
184→    async fn enable(&self, params: Value) -> ServiceResult {
185→        let name = params
186→            .get("name")
187→            .and_then(|v| v.as_str())
188→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
189→        let redirect_uri = params
190→            .get("redirectUri")
191→            .and_then(|v| v.as_str())
192→            .map(str::trim)
193→            .filter(|v| !v.is_empty())
194→            .map(ToOwned::to_owned);
195→        self.refresh_manager_env_overrides().await;
196→
197→        match self.manager.enable_server(name).await {
198→            Ok(_) => {
199→                self.sync_tools_if_ready().await;
200→                Ok(serde_json::json!({ "enabled": true }))
201→            },
202→            Err(e) => {
203→                if matches!(
204→                    e,
205→                    moltis_mcp::Error::Manager(moltis_mcp::McpManagerError::OAuthRequired { .. })
206→                ) {
207→                    if let Some(uri) = redirect_uri {
208→                        let auth_url = self
209→                            .manager
210→                            .oauth_start_server(name, &uri)
211→                            .await
212→                            .map_err(ServiceError::message)?;
213→                        Ok(serde_json::json!({
214→                            "enabled": false,
215→                            "oauthPending": true,
216→                            "authUrl": auth_url
217→                        }))
218→                    } else {
219→                        Ok(serde_json::json!({
220→                            "enabled": false,
221→                            "oauthPending": true
222→                        }))
223→                    }
224→                } else {
225→                    Err(ServiceError::message(e))
226→                }
227→            },
228→        }
229→    }
230→
231→    async fn disable(&self, params: Value) -> ServiceResult {
232→        let name = params
233→            .get("name")
234→            .and_then(|v| v.as_str())
235→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
236→
237→        let ok = self
238→            .manager
239→            .disable_server(name)
240→            .await
241→            .map_err(ServiceError::message)?;
242→
243→        self.sync_tools_if_ready().await;
244→
245→        Ok(serde_json::json!({ "disabled": ok }))
246→    }
247→
248→    async fn status(&self, params: Value) -> ServiceResult {
249→        let name = params
250→            .get("name")
251→            .and_then(|v| v.as_str())
252→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
253→
254→        match self.manager.status(name).await {
255→            Some(s) => Ok(serde_json::to_value(&s)?),
256→            None => Err(format!("MCP server '{name}' not found").into()),
257→        }
258→    }
259→
260→    async fn tools(&self, params: Value) -> ServiceResult {
261→        let name = params
262→            .get("name")
263→            .and_then(|v| v.as_str())
264→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
265→
266→        match self.manager.server_tools(name).await {
267→            Some(tools) => Ok(serde_json::to_value(&tools)?),
268→            None => Err(format!("MCP server '{name}' not found or not running").into()),
269→        }
