325→    /// Restart a server.
326→    pub async fn restart_server(&self, name: &str) -> Result<()> {
327→        let config = {
328→            let inner = self.inner.read().await;
329→            inner
330→                .registry
331→                .get(name)
332→                .cloned()
333→                .with_context(|| format!("MCP server '{name}' not found in registry"))?
334→        };
335→        self.start_server(name, &config).await
336→    }
