338→    /// Start OAuth for an SSE server and return the browser authorization URL.
339→    pub async fn oauth_start_server(&self, name: &str, redirect_uri: &str) -> Result<String> {
340→        let config =
341→            {
342→                let inner = self.inner.read().await;
343→                inner.registry.get(name).cloned().ok_or_else(|| {
344→                    McpManagerError::ServerNotFound {
345→                        server: name.to_string(),
346→                    }
347→                })?
348→            };
349→
350→        if !matches!(
351→            config.transport,
352→            TransportType::Sse | TransportType::StreamableHttp
353→        ) {
354→            return Err(McpManagerError::NotRemoteTransport {
355→                server: name.to_string(),
356→            }
357→            .into());
358→        }
359→
360→        let env_overrides = {
361→            let inner = self.inner.read().await;
362→            inner.env_overrides.clone()
363→        };
364→        let remote = ResolvedRemoteConfig::from_server_config(&config, &env_overrides)?;
365→
366→        let existing_auth = {
367→            let inner = self.inner.read().await;
368→            inner.auth_providers.get(name).cloned()
369→        };
370→        let has_existing_auth_provider = existing_auth.is_some();
371→        let auth_provider = existing_auth
372→            .unwrap_or_else(|| Self::build_auth_provider(name, &remote, config.oauth.as_ref()));
373→
374→        if !has_existing_auth_provider {
375→            let mut inner = self.inner.write().await;
376→            inner
377→                .auth_providers
378→                .insert(name.to_string(), auth_provider.clone());
379→        }
380→
381→        auth_provider
382→            .start_oauth(redirect_uri, None)
383→            .await?
384→            .with_context(|| format!("MCP server '{name}' does not support OAuth"))
385→    }
386→
387→    /// Complete an OAuth callback by matching state across MCP auth providers.
388→    ///
389→    /// Returns the server name whose OAuth flow was completed.
390→    pub async fn oauth_complete_callback(&self, state: &str, code: &str) -> Result<String> {
391→        let providers: Vec<(String, SharedAuthProvider)> = {
392→            let inner = self.inner.read().await;
393→            inner
394→                .auth_providers
395→                .iter()
396→                .map(|(name, provider)| (name.clone(), provider.clone()))
397→                .collect()
398→        };
399→
400→        for (name, provider) in providers {
401→            if provider.complete_oauth(state, code).await? {
402→                self.restart_server(&name).await?;
403→                return Ok(name);
404→            }
405→        }
406→
407→        Err(McpManagerError::OAuthStateNotFound.into())
408→    }
409→
410→    /// Trigger re-authentication for an SSE server.
411→    pub async fn reauth_server(&self, name: &str, redirect_uri: &str) -> Result<String> {
412→        self.oauth_start_server(name, redirect_uri).await
413→    }
