415→    /// Get the status of all configured servers.
416→    pub async fn status_all(&self) -> Vec<ServerStatus> {
417→        let inner = self.inner.read().await;
418→
419→        let mut statuses = Vec::new();
420→        for (name, config) in &inner.registry.servers {
421→            let state = if let Some(client) = inner.clients.get(name) {
422→                let c = client.read().await;
423→                match c.state() {
424→                    McpClientState::Ready => {
425→                        if c.is_alive().await {
426→                            "running"
427→                        } else {
428→                            "dead"
429→                        }
430→                    },
431→                    McpClientState::Connected => "connecting",
432→                    McpClientState::Authenticating => "authenticating",
433→                    McpClientState::Closed => "stopped",
434→                }
435→            } else {
436→                "stopped"
437→            };
438→
439→            let auth_state = inner.auth_providers.get(name).map(|a| a.auth_state());
440→            statuses.push(ServerStatus {
441→                name: name.clone(),
442→                state: state.into(),
443→                enabled: config.enabled,
444→                tool_count: inner.tools.get(name).map_or(0, |t| t.len()),
445→                server_info: None,
446→                command: config.command.clone(),
447→                args: config.args.clone(),
448→                env: if matches!(
449→                    config.transport,
450→                    TransportType::Sse | TransportType::StreamableHttp
451→                ) {
452→                    HashMap::new()
453→                } else {
454→                    config.env.clone()
455→                },
456→                request_timeout_secs: config.request_timeout_secs,
457→                configured_request_timeout_secs: self.effective_timeout_secs_for(config),
458→                transport: config.transport,
459→                url: config
460→                    .url
461→                    .as_ref()
462→                    .map(|raw| sanitize_url_for_display(raw.expose_secret())),
463→                header_names: header_names(&config.headers),
464→                auth_state,
465→                auth_url: None,
466→                display_name: config.display_name.clone(),
467→            });
468→        }
469→        statuses
470→    }
