502→    /// Add a server to the registry and optionally start it.
503→    pub async fn add_server(
504→        &self,
505→        name: String,
506→        config: McpServerConfig,
507→        start: bool,
508→    ) -> Result<()> {
509→        let enabled = config.enabled;
510→        {
511→            let mut inner = self.inner.write().await;
512→            inner.registry.add(name.clone(), config.clone())?;
513→        }
514→        if start && enabled {
515→            self.start_server(&name, &config).await?;
516→        }
517→        Ok(())
518→    }
