520→    /// Remove a server from the registry and stop it.
521→    pub async fn remove_server(&self, name: &str) -> Result<bool> {
522→        self.stop_server(name).await;
523→        let mut inner = self.inner.write().await;
524→        inner.auth_providers.remove(name);
525→        inner.registry.remove(name)
526→    }
527→
528→    /// Enable a server and start it.
529→    pub async fn enable_server(&self, name: &str) -> Result<bool> {
530→        let config = {
531→            let mut inner = self.inner.write().await;
532→            if !inner.registry.enable(name)? {
533→                return Ok(false);
534→            }
535→            inner.registry.get(name).cloned()
536→        };
537→        if let Some(config) = config {
538→            self.start_server(name, &config).await?;
539→        }
540→        Ok(true)
541→    }
542→
543→    /// Disable a server and stop it.
544→    pub async fn disable_server(&self, name: &str) -> Result<bool> {
545→        self.stop_server(name).await;
546→        let mut inner = self.inner.write().await;
547→        inner.registry.disable(name)
548→    }
