550→    /// Get a snapshot of the registry for serialization.
551→    pub async fn registry_snapshot(&self) -> McpRegistry {
552→        self.inner.read().await.registry.clone()
553→    }
554→
555→    /// Update a server's configuration and restart it if running.
556→    pub async fn update_server(&self, name: &str, config: McpServerConfig) -> Result<()> {
557→        let was_running = {
558→            let inner = self.inner.read().await;
559→            inner.clients.contains_key(name)
560→        };
561→        {
562→            let mut inner = self.inner.write().await;
563→            let enabled = inner.registry.get(name).is_none_or(|c| c.enabled);
564→            let mut new_config = config;
565→            new_config.enabled = enabled;
566→            inner.registry.add(name.to_string(), new_config)?;
567→        }
568→        if was_running {
569→            self.restart_server(name).await?;
570→        }
571→        Ok(())
572→    }
573→
574→    /// Shut down all servers.
575→    pub async fn shutdown_all(&self) {
576→        let names: Vec<String> = self.inner.read().await.clients.keys().cloned().collect();
577→        for name in names {
578→            self.stop_server(&name).await;
579→        }
580→    }
581→}
