 1→// Shared Playwright test fixture with automatic error-context capture.
 2→//
 3→// Every spec file should import { test, expect } from this module instead of
 4→// from "@playwright/test".  On failure the fixture attaches a markdown
 5→// snapshot of every open page (URL, title, visible text) so CI logs contain
 6→// enough context to diagnose failures without downloading trace artifacts.
 7→
 8→const { test: base, expect } = require("@playwright/test");
 9→
10→var test = base.extend({
11→	page: async ({ page, context }, use, testInfo) => {
12→		await use(page);
13→
14→		if (testInfo.status !== testInfo.expectedStatus) {
15→			var pages = context.pages();
16→			var parts = [];
17→
18→			for (var i = 0; i < pages.length; i++) {
19→				var p = pages[i];
20→				try {
21→					if (p.isClosed()) {
22→						parts.push(`### Page ${i + 1}: (closed)`);
23→						continue;
24→					}
25→					var url = p.url();
26→					var title = await p.title().catch(() => "(unknown)");
27→					var text = await p
28→						.evaluate(() => document.body?.innerText?.slice(0, 3000) || "")
29→						.catch(() => "(unavailable)");
30→					parts.push(`### Page ${i + 1}: ${title}\n- **URL**: ${url}\n\n\`\`\`\n${text}\n\`\`\``);
31→				} catch {
32→					parts.push(`### Page ${i + 1}: (error reading page)`);
33→				}
34→			}
35→
36→			var md = ["## Error Context", "", `**Test**: ${testInfo.title}`, `**Status**: ${testInfo.status}`, ""]
37→				.concat(parts)
38→				.join("\n");
39→
40→			await testInfo.attach("error-context", {
41→				body: Buffer.from(md, "utf-8"),
42→				contentType: "text/markdown",
43→			});
44→		}
45→	},
46→});
47→
48→module.exports = { test, expect };
